section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Auto Hero (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Auto Hero (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Auto Hero (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="auto-hero">\n    <div class="dw-d-bg dw-d-bg--left dw-d-bg--gradient" style="opacity: 0.14;"></div>\n            <div class="auto-hero-inner" style="position: relative; z-index: 2;">\n                <div class="auto-hero-badge">\n                    <span>อุตสาหกรรมชิ้นส่วนยานยนต์</span>\n                </div>\n                <h1>สร้างมาเพื่อสิ่งที่ <span>OEM ต้องการ</span></h1>\n                <p class="auto-hero-subtitle">ส่งตรงเวลาแบบ JIT ตรวจสอบย้อนกลับได้ครบถ้วน เชื่อมต่อ EDI ครบวงจร ประเทศไทยคือศูนย์กลางยานยนต์ของอาเซียน—เราช่วยผู้ผลิตชิ้นส่วน Tier 1-3 รักษาความสามารถในการแข่งขัน</p>\n                <div class="auto-hero-stats">\n                    <div class="auto-hero-stat">\n                        <div class="auto-hero-stat-value">500+</div>\n                        <div class="auto-hero-stat-label">ผู้ผลิตชิ้นส่วนยานยนต์ที่ให้บริการ</div>\n                    </div>\n                    <div class="auto-hero-stat">\n                        <div class="auto-hero-stat-value">100%</div>\n                        <div class="auto-hero-stat-label">ครอบคลุมการตรวจสอบย้อนกลับ</div>\n                    </div>\n                    <div class="auto-hero-stat">\n                        <div class="auto-hero-stat-value">99.5%</div>\n                        <div class="auto-hero-stat-label">ส่งมอบตรงเวลา</div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Context (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="context-section">\n    <div class="context-inner">\n                <h2>ประเทศไทย: ดีทรอยต์แห่งอาเซียน</h2>\n                <p>ประเทศไทยผลิต<strong>ยานยนต์ 1.9 ล้านคันต่อปี</strong> ทำให้เป็นศูนย์กลางการผลิตยานยนต์ที่ใหญ่ที่สุดในเอเชียตะวันออกเฉียงใต้ เบื้องหลังยานยนต์ทุกคันคือ<strong>ผู้ผลิตชิ้นส่วน Tier 1-3 กว่า 2,500+ ราย</strong>ที่เผชิญกับความต้องการอย่างไม่หยุดหย่อน: คุณภาพสมบูรณ์แบบ ตรวจสอบย้อนกลับได้ครบถ้วน และ JIT delivery ที่นับเป็นชั่วโมง ไม่ใช่วัน DigiWin มีประสบการณ์กว่า 20 ปีในการช่วยผู้ผลิตชิ้นส่วนเหล่านี้ให้บรรลุ—และเหนือกว่า—ความคาดหวังของ OEM</p>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Stakes (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Stakes (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Stakes (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="stakes-section">\n    <div class="dw-section-scene">\n                <svg aria-hidden="true" viewBox="0 0 1400 900" fill="none" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid slice">\n                    <line x1="0" y1="450" x2="1400" y2="450" stroke="#000864" stroke-width="1.5" opacity="0.1"/>\n                    <rect x="100" y="400" width="90" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="145" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">STAMP</text>\n                    <path d="M190 450 L320 450" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <polygon points="315,445 330,450 315,455" fill="#000864" opacity="0.12"/>\n                    <rect x="330" y="400" width="90" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="375" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">WELD</text>\n                    <path d="M420 450 L550 450" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <polygon points="545,445 560,450 545,455" fill="#000864" opacity="0.12"/>\n                    <rect x="560" y="400" width="90" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="605" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">PAINT</text>\n                    <path d="M650 450 L780 450" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <polygon points="775,445 790,450 775,455" fill="#000864" opacity="0.12"/>\n                    <rect x="790" y="400" width="90" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="835" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">ASSEM</text>\n                    <path d="M880 450 L1010 450" stroke="#000864" stroke-width="1.5" opacity="0.12"/>\n                    <polygon points="1005,445 1020,450 1005,455" fill="#000864" opacity="0.12"/>\n                    <rect x="1020" y="400" width="90" height="100" rx="6" stroke="#000864" stroke-width="2" fill="none" opacity="0.15"/>\n                    <text x="1065" y="460" font-family="\'Noto Sans\',sans-serif" font-size="8" font-weight="600" fill="#000864" opacity="0.1" text-anchor="middle">QC</text>\n                    <text x="1200" y="300" font-family="\'Noto Sans\',sans-serif" font-size="16" font-weight="700" fill="#00AFF0" opacity="0.1">JIT</text>\n                    <rect x="1150" y="310" width="120" height="40" rx="4" stroke="#00AFF0" stroke-width="1.5" fill="none" opacity="0.1"/>\n                    <text x="1210" y="335" font-family="\'Noto Sans\',sans-serif" font-size="9" font-weight="600" fill="#00AFF0" opacity="0.08" text-anchor="middle">EDI LINK</text>\n                    <circle cx="300" cy="250" r="3" fill="#000864" opacity="0.08"/>\n                    <circle cx="700" cy="650" r="4" fill="#00AFF0" opacity="0.08"/>\n                    <circle cx="1100" cy="700" r="3" fill="#000864" opacity="0.06"/>\n                </svg>\n            </div>\n            <div class="stakes-inner" style="position: relative; z-index: 2;">\n                <div class="stakes-header">\n                    <h2>เดิมพันสูงในอุตสาหกรรมยานยนต์</h2>\n                    <p>ในอุตสาหกรรมยานยนต์ ไม่มีพื้นที่สำหรับ "ดีพอแล้ว"</p>\n                </div>\n                <div class="stakes-grid">\n                    <div class="stake-card">\n                        <div class="stake-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="12" cy="12" r="10"/><polyline points="12 6 12 12 16 14"/></svg>\n                        </div>\n                        <h3>JIT หรือจบ</h3>\n                        <p>พลาดหน้าต่างการส่งมอบครั้งเดียว OEM หยุดสายการผลิต ค่าปรับไม่ใช่แค่คำเตือน—แต่คือต้นทุนเวลาหยุดเครื่อง บวกกับการสูญเสียสัญญาทั้งหมด</p>\n                    </div>\n                    <div class="stake-card">\n                        <div class="stake-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg>\n                        </div>\n                        <h3>ตรวจสอบได้ หรือสูญเสีย</h3>\n                        <p>ปัญหาคุณภาพถูกพบ OEM ถาม: ล็อตไหน? วัตถุดิบอะไร? พนักงานคนไหน? ถ้าตอบไม่ได้ภายในไม่กี่ชั่วโมง คุณไม่ใช่ Tier-1 supplier อีกต่อไป</p>\n                    </div>\n                    <div class="stake-card">\n                        <div class="stake-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M16 4h2a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H6a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2h2"/><rect x="8" y="2" width="8" height="4" rx="1" ry="1"/><line x1="9" y1="12" x2="15" y2="12"/><line x1="9" y1="16" x2="15" y2="16"/></svg>\n                        </div>\n                        <h3>ความกังวลเรื่องการตรวจสอบ</h3>\n                        <p>IATF 16949 ลูกค้าตรวจสอบทุกไตรมาส เอกสารที่ต้องจัดทำเพิ่มขึ้นเรื่อยๆ ระบบที่ทำด้วยมือตามไม่ทัน</p>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Solutions (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="solutions-section">\n    <div class="dw-d-bg dw-d-bg--corner-br" style="opacity: 0.08;"></div>\n            <div class="solutions-inner" style="position: relative; z-index: 2;">\n                <div class="solutions-header">\n                    <h2>DigiWin แก้ปัญหาอย่างไร</h2>\n                    <p>ความสามารถที่สร้างมาเฉพาะสำหรับซัพพลายเชนยานยนต์</p>\n                </div>\n                <div class="solutions-grid">\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M6.5 12a5.5 5.5 0 1 0 11 0 5.5 5.5 0 1 0-11 0"/><path d="M3 12a9 9 0 1 0 18 0 9 9 0 1 0-18 0"/><circle cx="12" cy="12" r="2"/></svg>\n                        </div>\n                        <h3>เชื่อมต่อ EDI กับ OEM</h3>\n                        <p>รับส่งข้อมูลอิเล็กทรอนิกส์ของ Forecast, ใบสั่งซื้อ และยืนยันการส่งมอบกับลูกค้า OEM ไม่ต้องป้อนข้อมูลด้วยมือ ไม่พลาดสัญญาณ</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>รับ Forecast และ PO อัตโนมัติ</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>ส่ง ASN และยืนยันการส่งมอบ</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>รับส่งข้อมูลคุณภาพ</span>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M20.59 13.41l-7.17 7.17a2 2 0 0 1-2.83 0L2 12V2h10l8.59 8.59a2 2 0 0 1 0 2.82z"/><line x1="7" y1="7" x2="7.01" y2="7"/></svg>\n                        </div>\n                        <h3>ตรวจสอบย้อนกลับระดับล็อต</h3>\n                        <p>ติดตามทุกชิ้นส่วนตั้งแต่รับเข้าจนถึงจัดส่ง ตอบคำถาม "ชิ้นส่วนนี้ไปไหน?" ได้ภายในไม่กี่วินาที ไม่ใช่เป็นวัน</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>ตรวจสอบย้อนกลับทั้งไปข้างหน้าและย้อนกลับ</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>สแกนบาร์โค้ด/QR Code</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>วิเคราะห์ขอบเขตการเรียกคืน</span>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="3" y="4" width="18" height="18" rx="2" ry="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>\n                        </div>\n                        <h3>Kanban และ JIT Scheduling</h3>\n                        <p>การวางแผนการผลิตที่เข้าใจสัญญาณ Kanban, Sequence Order และหน้าต่างการส่งมอบ</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>วางแผนย้อนกลับจากวันส่งสินค้า</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>รองรับ Sequence Delivery</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>ประสานงานหลายโรงงาน</span>\n                            </div>\n                        </div>\n                    </div>\n                    <div class="solution-card">\n                        <div class="solution-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M9 11l3 3L22 4"/><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h11"/></svg>\n                        </div>\n                        <h3>เอกสารคุณภาพ</h3>\n                        <p>รองรับ PPAP แผนควบคุม บันทึกการตรวจสอบ ข้อมูล SPC บันทึกแบบดิจิทัลทั้งหมด พร้อมตรวจสอบได้ทันที</p>\n                        <div class="solution-features">\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>รองรับ IATF 16949</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>แผนภูมิ SPC และการวิเคราะห์</span>\n                            </div>\n                            <div class="solution-feature">\n                                <svg aria-hidden="true" viewBox="0 0 20 20" fill="currentColor"><path fill-rule="evenodd" d="M16.707 5.293a1 1 0 010 1.414l-8 8a1 1 0 01-1.414 0l-4-4a1 1 0 011.414-1.414L8 12.586l7.293-7.293a1 1 0 011.414 0z"/></svg>\n                                <span>รายงาน 8D</span>\n                            </div>\n                        </div>\n                    </div>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Products (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="products-section">\n    <div class="products-inner">\n                <div class="products-header">\n                    <h2>ผลิตภัณฑ์แนะนำสำหรับยานยนต์</h2>\n                </div>\n                <div class="products-grid">\n                    <a href="../products/erp.html" class="product-card">\n                        <div class="product-card-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="3" y="3" width="18" height="18" rx="2"/><path d="M3 9h18"/><path d="M9 21V9"/></svg>\n                        </div>\n                        <h3>T100 ERP</h3>\n                        <p>ERP หลายโรงงาน หลายสกุลเงิน พร้อมโมดูลเฉพาะยานยนต์สำหรับ EDI, JIT scheduling และจัดการซัพพลายเออร์</p>\n                        <span class="product-card-link">เรียนรู้เพิ่มเติม <span>→</span></span>\n                    </a>\n                    <a href="../products/mes.html" class="product-card">\n                        <div class="product-card-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><rect x="2" y="7" width="20" height="14" rx="2"/><path d="M6 7V5a2 2 0 0 1 2-2h8a2 2 0 0 1 2 2v2"/><circle cx="6" cy="12" r="1"/><circle cx="10" cy="12" r="1"/><circle cx="14" cy="12" r="1"/><circle cx="18" cy="12" r="1"/></svg>\n                        </div>\n                        <h3>MES</h3>\n                        <p>ตรวจสอบย้อนกลับครบถ้วน เก็บข้อมูลคุณภาพ และมองเห็นการผลิตแบบ Real-time สำหรับความต้องการความแม่นยำในอุตสาหกรรมยานยนต์</p>\n                        <span class="product-card-link">เรียนรู้เพิ่มเติม <span>→</span></span>\n                    </a>\n                    <a href="../products/wms.html" class="product-card">\n                        <div class="product-card-icon">\n                            <svg aria-hidden="true" viewBox="0 0 24 24"><path d="M21 16V8a2 2 0 0 0-1-1.73l-7-4a2 2 0 0 0-2 0l-7 4A2 2 0 0 0 3 8v8a2 2 0 0 0 1 1.73l7 4a2 2 0 0 0 2 0l7-4A2 2 0 0 0 21 16z"/><polyline points="3.29 7 12 12 20.71 7"/><line x1="12" y1="22" x2="12" y2="12"/></svg>\n                        </div>\n                        <h3>sFLS WMS</h3>\n                        <p>บังคับ FIFO ติดตามล็อต และรองรับ Sequence Delivery สำหรับคลังสินค้า JIT</p>\n                        <span class="product-card-link">เรียนรู้เพิ่มเติม <span>→</span></span>\n                    </a>\n                </div>\n            </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dw-section" style="padding: 80px 5%; background: #F5F7FA; position: relative; overflow: hidden;">\n    <div style="max-width: 1200px; margin: 0 auto;">\n                <div style="text-align: center; margin-bottom: 48px;">\n                    <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 13px; font-weight: 500; letter-spacing: 0.02em; color: #00AFF0; margin: 0 0 12px 0;">ผลลัพธ์ที่ยืนยันแล้ว</p>\n                    <h2 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 36px; font-weight: 700; color: #000864; margin: 0 0 16px 0;">ผลลัพธ์ยานยนต์ที่พิสูจน์แล้ว</h2>\n                    <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 18px; color: #666; max-width: 680px; margin: 0 auto; line-height: 1.6;">ผลลัพธ์ที่วัดได้จากการติดตั้ง DigiWin กว่า 1,000+ ครั้งในอุตสาหกรรมยานยนต์ทั่วเอเชีย</p>\n                </div>\n                <div class="auto-results-grid" style="display: grid; grid-template-columns: repeat(4, 1fr); gap: 24px;">\n                    <div class="fade-in" style="background: white; border-radius: 12px; padding: 32px 24px; text-align: center; border: 1px solid #e5e7eb; transition: box-shadow 0.3s ease;">\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 40px; font-weight: 700; color: #0369a1; line-height: 1; margin-bottom: 8px;">-30%</div>\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 600; color: #000864; margin-bottom: 6px;">ระยะเวลา R&D</div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 13px; color: #666; margin: 0; line-height: 1.6;">พัฒนาผลิตภัณฑ์เร็วขึ้นตั้งแต่ออกแบบจนถึงตรวจสอบการผลิต</p>\n                    </div>\n                    <div class="fade-in" style="background: white; border-radius: 12px; padding: 32px 24px; text-align: center; border: 1px solid #e5e7eb; transition: box-shadow 0.3s ease;">\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 40px; font-weight: 700; color: #0369a1; line-height: 1; margin-bottom: 8px;">+35%</div>\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 600; color: #000864; margin-bottom: 6px;">ส่งมอบตรงเวลา</div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 13px; color: #666; margin: 0; line-height: 1.6;">JIT compliance ที่ดีขึ้น ปกป้องสัญญา OEM และป้องกันค่าปรับหยุดสายการผลิต</p>\n                    </div>\n                    <div class="fade-in" style="background: white; border-radius: 12px; padding: 32px 24px; text-align: center; border: 1px solid #e5e7eb; transition: box-shadow 0.3s ease;">\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 40px; font-weight: 700; color: #0369a1; line-height: 1; margin-bottom: 8px;">30-60%</div>\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 600; color: #000864; margin-bottom: 6px;">ลดสินค้าคงคลัง</div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 13px; color: #666; margin: 0; line-height: 1.6;">ลดต้นทุนการถือสินค้าด้วยการวางแผนความต้องการที่แม่นยำและ WMS ที่บูรณาการ</p>\n                    </div>\n                    <div class="fade-in" style="background: white; border-radius: 12px; padding: 32px 24px; text-align: center; border: 1px solid #e5e7eb; transition: box-shadow 0.3s ease;">\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 40px; font-weight: 700; color: #0369a1; line-height: 1; margin-bottom: 8px;">100%</div>\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 600; color: #000864; margin-bottom: 6px;">ตรวจสอบย้อนกลับคุณภาพ</div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 13px; color: #666; margin: 0; line-height: 1.6;">ติดตามล็อตครบตั้งแต่วัตถุดิบถึงสินค้าสำเร็จรูป—ไม่มีช่องว่างการตรวจสอบย้อนกลับ</p>\n                    </div>\n                    <div class="fade-in" style="background: white; border-radius: 12px; padding: 32px 24px; text-align: center; border: 1px solid #e5e7eb; transition: box-shadow 0.3s ease;">\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 40px; font-weight: 700; color: #0369a1; line-height: 1; margin-bottom: 8px;">60→80%+</div>\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 600; color: #000864; margin-bottom: 6px;">OEE ดีขึ้น</div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 13px; color: #666; margin: 0; line-height: 1.6;">ประสิทธิผลเครื่องจักรที่ดีขึ้นผ่านการติดตาม MES แบบ Real-time และวิเคราะห์เวลาหยุดเครื่อง</p>\n                    </div>\n                    <div class="fade-in" style="background: white; border-radius: 12px; padding: 32px 24px; text-align: center; border: 1px solid #e5e7eb; transition: box-shadow 0.3s ease;">\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 40px; font-weight: 700; color: #0369a1; line-height: 1; margin-bottom: 8px;">+40%</div>\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 600; color: #000864; margin-bottom: 6px;">ความแม่นยำในการวางแผน</div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 13px; color: #666; margin: 0; line-height: 1.6;">จัดตารางการผลิตแม่นยำขึ้น ลดการทำงานล่วงเวลาและออเดอร์เร่งด่วน</p>\n                    </div>\n                    <div class="fade-in" style="background: white; border-radius: 12px; padding: 32px 24px; text-align: center; border: 1px solid #e5e7eb; transition: box-shadow 0.3s ease;">\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 40px; font-weight: 700; color: #0369a1; line-height: 1; margin-bottom: 8px;">-25%</div>\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 600; color: #000864; margin-bottom: 6px;">อัตราของเสีย</div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 13px; color: #666; margin: 0; line-height: 1.6;">ลดวัสดุเหลือใช้ด้วยการควบคุมคุณภาพในทุกขั้นตอนการผลิต</p>\n                    </div>\n                    <div class="fade-in" style="background: white; border-radius: 12px; padding: 32px 24px; text-align: center; border: 1px solid #e5e7eb; transition: box-shadow 0.3s ease;">\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 40px; font-weight: 700; color: #0369a1; line-height: 1; margin-bottom: 8px;">สัปดาห์→วัน</div>\n                        <div style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; font-weight: 600; color: #000864; margin-bottom: 6px;">ปิดบัญชีสิ้นเดือน</div>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 13px; color: #666; margin: 0; line-height: 1.6;">บัญชีต้นทุนและรวมงบการเงินข้ามโรงงานแบบอัตโนมัติ</p>\n                    </div>\n                </div>\n            </div>\n            <style>\n                @media (max-width: 1024px) {\n                    .auto-results-grid { grid-template-columns: repeat(2, 1fr) !important; }\n                }\n                @media (max-width: 600px) {\n                    .auto-results-grid { grid-template-columns: 1fr !important; }\n                }\n            </style>    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 2 (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 2 (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 2 (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="dw-section" style="padding: 80px 5%; background: white; position: relative; overflow: hidden;">\n    <div style="max-width: 1000px; margin: 0 auto;">\n                <div style="text-align: center; margin-bottom: 48px;">\n                    <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 13px; font-weight: 500; letter-spacing: 0.02em; color: #00AFF0; margin: 0 0 12px 0;">ลูกค้าอ้างอิง</p>\n                    <h2 style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 36px; font-weight: 700; color: #000864; margin: 0 0 16px 0;">ผลงาน DigiWin ในอุตสาหกรรมยานยนต์ทั่วเอเชีย</h2>\n                    <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 18px; color: #666; max-width: 700px; margin: 0 auto; line-height: 1.6;">ความเชี่ยวชาญด้านยานยนต์ของ DigiWin ครอบคลุมกว่า 1,000+ การติดตั้งทั่วเอเชีย นี่คือสิ่งที่ลูกค้ายานยนต์ของเราบรรลุ:</p>\n                </div>\n                <div class="auto-track-grid" style="display: grid; grid-template-columns: repeat(3, 1fr); gap: 24px;">\n                    <div class="fade-in" style="background: #F5F7FA; border-radius: 12px; padding: 32px; border-left: 4px solid #00AFF0; transition: box-shadow 0.3s ease;">\n                        <div style="font-family: \'JetBrains Mono\', monospace; font-size: 12px; font-weight: 500; letter-spacing: 0.08em; text-transform: uppercase; color: #0369a1; margin-bottom: 12px;">ERP + MES</div>\n                        <h3 style="font-family: \'Noto Sans\', sans-serif; font-size: 18px; font-weight: 700; color: #000864; margin: 0 0 12px 0;">Zhejiang Yahu Auto Parts</h3>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; color: #333; margin: 0; line-height: 1.7;">สินค้าคงคลังลดจาก 30M เหลือ 12M RMB ด้วย ERP + MES แบบบูรณาการ—ลดได้ 60% จากการเชื่อมต่อการวางแผนกับข้อมูลสายการผลิตแบบ Real-time</p>\n                    </div>\n                    <div class="fade-in" style="background: #F5F7FA; border-radius: 12px; padding: 32px; border-left: 4px solid #02D28C; transition: box-shadow 0.3s ease;">\n                        <div style="font-family: \'JetBrains Mono\', monospace; font-size: 12px; font-weight: 500; letter-spacing: 0.08em; text-transform: uppercase; color: #0369a1; margin-bottom: 12px;">ERP + MES</div>\n                        <h3 style="font-family: \'Noto Sans\', sans-serif; font-size: 18px; font-weight: 700; color: #000864; margin: 0 0 12px 0;">Ningbo GREAT Automotive</h3>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; color: #333; margin: 0; line-height: 1.7;">ตรวจสอบย้อนกลับล็อตครบตั้งแต่วัตถุดิบถึงสินค้าสำเร็จรูป—ไม่มีการเรียกคืนที่ล้มเหลว ทุกชิ้นส่วนถูกติดตามตลอดห่วงโซ่การผลิต</p>\n                    </div>\n                    <div class="fade-in" style="background: #F5F7FA; border-radius: 12px; padding: 32px; border-left: 4px solid #644CE6; transition: box-shadow 0.3s ease;">\n                        <div style="font-family: \'JetBrains Mono\', monospace; font-size: 12px; font-weight: 500; letter-spacing: 0.08em; text-transform: uppercase; color: #0369a1; margin-bottom: 12px;">MES</div>\n                        <h3 style="font-family: \'Noto Sans\', sans-serif; font-size: 18px; font-weight: 700; color: #000864; margin: 0 0 12px 0;">Wieson Automotive Electronics</h3>\n                        <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; color: #333; margin: 0; line-height: 1.7;">บูรณาการ MES ติดตามการผลิตแบบ Real-time ข้ามหลายสายการผลิต—เชื่อมต่อข้อมูลเครื่องจักรกับการตัดสินใจของผู้บริหารทันที</p>\n                    </div>\n                </div>\n            </div>\n            <style>\n                @media (max-width: 768px) {\n                    .auto-track-grid { grid-template-columns: 1fr !important; }\n                }\n            </style>    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 3 (Thai)"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 3 (Thai): Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section 3 (Thai): Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="auto-faq">\n    <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n            <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 28px; font-weight: 700; color: #000864; margin-bottom: 32px; text-align: center;">คำถามที่พบบ่อย</h2>\n            <div style="display: flex; flex-direction: column; gap: 12px;">\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">โรงงานชิ้นส่วนยานยนต์ในประเทศไทยใช้ระบบ ERP อะไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">DigiWin เป็น ERP (ระบบบริหารทรัพยากรองค์กร) ที่ผู้ผลิตชิ้นส่วนยานยนต์ Tier 1-3 กว่า 500 รายทั่วไทยและอาเซียนเลือกใช้ ระบบของเราสร้างมาเฉพาะสำหรับซัพพลายเชนยานยนต์ รองรับ JIT scheduling, OEM EDI integration และ IATF 16949 quality compliance โดยกำเนิด ต่างจาก ERP ทั่วไป DigiWin เข้าใจสัญญาณ Kanban, Sequence Delivery และการประสานงานหลายโรงงานที่อุตสาหกรรมยานยนต์ต้องการ</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin ERP รองรับ EDI สำหรับซัพพลายเชนยานยนต์หรือไม่?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">รองรับ DigiWin ERP รองรับการเชื่อมต่อ EDI สำหรับซัพพลายเชนยานยนต์ ทำให้สามารถรับส่งข้อมูล Forecast, ใบสั่งซื้อ, ยืนยัน ASN และข้อมูลคุณภาพกับลูกค้า OEM ได้โดยอิเล็กทรอนิกส์ ลดการป้อนข้อมูลด้วยมือและช่วยรักษาหน้าต่าง JIT delivery ที่เข้มงวดในการผลิตยานยนต์</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin รองรับเอกสารคุณภาพ IATF 16949 หรือไม่?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">รองรับ DigiWin มีโมดูลจัดการคุณภาพในตัวที่ออกแบบมาสำหรับ IATF 16949 compliance รองรับเอกสาร PPAP, แผนควบคุม, บันทึกการตรวจสอบ, แผนภูมิ SPC และการวิเคราะห์ และรายงาน 8D ข้อมูลคุณภาพทั้งหมดถูกบันทึกแบบดิจิทัลและพร้อมตรวจสอบได้ตลอดเวลา ขจัดความกังวลเรื่องเอกสารที่มาพร้อมกับการตรวจสอบของลูกค้าทุกไตรมาส</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">DigiWin ช่วยเรื่องการตรวจสอบย้อนกลับล็อตยานยนต์อย่างไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">DigiWin ให้การตรวจสอบย้อนกลับ 100% ตั้งแต่รับวัตถุดิบจนถึงจัดส่งสินค้าสำเร็จรูป ระบบรองรับทั้งการตรวจสอบย้อนกลับไปข้างหน้าและย้อนกลับระดับล็อต ด้วยการสแกนบาร์โค้ดและ QR Code ในทุกขั้นตอน เมื่อปัญหาคุณภาพถูกพบและ OEM ถามว่าล็อตไหน วัตถุดิบอะไร พนักงานคนไหน DigiWin ให้คำตอบได้ภายในไม่กี่วินาทีไม่ใช่เป็นวัน พร้อมวิเคราะห์ขอบเขตการเรียกคืนอย่างแม่นยำ</p>\n                </div>\n              </details>\n              <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n                <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">ROI ของ ERP สำหรับยานยนต์โดยทั่วไปใช้เวลาเท่าไร?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n                <div style="padding: 0 20px 16px 20px; background: white;">\n                  <p style="font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.8; color: #333; margin: 0;">ลูกค้า DigiWin ในภาคยานยนต์มักเห็นผลลัพธ์ที่วัดได้ภายในปีแรกของการติดตั้ง ผลลัพธ์สำคัญรวมถึงอัตราส่งมอบตรงเวลาที่ 99.5% ซึ่งปกป้องสัญญา OEM โดยตรงและป้องกันค่าปรับหยุดสายการผลิตที่มีราคาสูง ด้วย JIT scheduling, การตรวจสอบย้อนกลับครบถ้วน และ EDI อัตโนมัติที่ทำงานร่วมกัน ROI (ผลตอบแทนจากการลงทุน) มาจากทั้งการหลีกเลี่ยงต้นทุนและประสิทธิภาพการดำเนินงานข้ามหลายโรงงาน</p>\n                </div>\n              </details>\n            </div>\n          </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: ส่งมอบตามข้อกำหนด OEM อย่างมั่นใจ"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: ส่งมอบตามข้อกำหนด OEM อย่างมั่นใจ: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"CTA: ส่งมอบตามข้อกำหนด OEM อย่างมั่นใจ: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><div class="auto-cta-section">\n    <div class="auto-cta-super-d" aria-hidden="true"></div>\n    <div class="auto-cta-wave-flow" aria-hidden="true"></div>\n    <div class="auto-cta-container">\n      <h2 class="auto-cta-title">ส่งมอบตามข้อกำหนด OEM อย่างมั่นใจ</h2>\n      <p class="auto-cta-subtitle">ดูว่า DigiWin ช่วยผู้ผลิตชิ้นส่วนยานยนต์ชั้นนำของไทยอย่างไร</p>\n      <div class="auto-cta-btn-row">\n        <a href="/th/demo/" class="auto-cta-btn auto-cta-btn--primary">ติดต่อเรา</a>\n        <a href="/industries.html" class="auto-cta-btn auto-cta-btn--ghost">ดูอุตสาหกรรมอื่น</a>\n      </div>\n    </div>\n    </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Section"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8"} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Column"}}},"decoration":{}}} -->\n<!-- wp:html --><style>\n.auto-related-grid{display:grid!important;grid-template-columns:repeat(auto-fit,minmax(280px,1fr))!important;gap:24px!important;max-width:1200px!important;margin:0 auto!important}\n.auto-related-card{display:block!important;padding:24px!important;background:#fff!important;border-radius:12px!important;text-decoration:none!important;border:1px solid #e5e7eb!important;color:#333!important;line-height:1.6!important}\n.auto-related-card-title{font-size:18px!important;font-weight:600!important;color:#000864!important;margin:0 0 8px 0!important}\n.auto-related-card-desc{font-size:14px!important;color:#666!important;margin:0!important}\n</style><div class="auto-related-section">\n    <h2 class="auto-related-heading">สำรวจโซลูชันที่เกี่ยวข้อง</h2>\n    <div class="auto-related-grid">\n      <a href="/industries/electronics/" class="auto-related-card">\n        <h3 class="auto-related-card-title">อิเล็กทรอนิกส์</h3>\n        <p class="auto-related-card-desc">ซอฟต์แวร์การผลิตสำหรับประกอบอิเล็กทรอนิกส์, สาย SMT และตรวจสอบย้อนกลับชิ้นส่วน</p>\n      </a>\n      <a href="/industries/metal-plastics/" class="auto-related-card">\n        <h3 class="auto-related-card-title">โลหะ &amp; พลาสติก</h3>\n        <p class="auto-related-card-desc">โซลูชันบูรณาการสำหรับหล่อ ฉีดพลาสติก และโรงงานขึ้นรูปโลหะ</p>\n      </a>\n      <a href="/products/erp/" class="auto-related-card">\n        <h3 class="auto-related-card-title">ERP</h3>\n        <p class="auto-related-card-desc">ERP สำหรับการผลิตที่สร้างมาเพื่อโรงงานไทย—ตั้งแต่ BOM ถึงการเงิน ถึง BOI compliance</p>\n      </a>\n      <a href="/products/mes/" class="auto-related-card">\n        <h3 class="auto-related-card-title">MES</h3>\n        <p class="auto-related-card-desc">ระบบปฏิบัติการผลิตแบบ Real-time—ติดตาม OEE, SPC, และใบสั่งผลิตแบบไม่ใช้กระดาษ</p>\n      </a>\n      <a href="/products/wms/" class="auto-related-card">\n        <h3 class="auto-related-card-title">WMS</h3>\n        <p class="auto-related-card-desc">จัดการคลังสินค้าอัจฉริยะด้วยบาร์โค้ด/RFID—ตั้งแต่รับเข้าจนถึงจัดส่ง ตรวจสอบย้อนกลับได้ครบ</p>\n      </a>\n      <a href="/products/aiot/" class="auto-related-card">\n        <h3 class="auto-related-card-title">AIoT</h3>\n        <p class="auto-related-card-desc">เชื่อมต่อเครื่องจักรเข้า ERP โดยตรงด้วยเซ็นเซอร์ IoT, Edge Computing และ AI Analytics</p>\n      </a>\n    </div>\n  </div><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
  post_modified = NOW(),
  post_modified_gmt = UTC_TIMESTAMP()
WHERE ID = 100782;

