DELETE FROM wp_postmeta WHERE post_id = 100782 AND meta_key = '_et_pb_custom_css';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100782, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === AUTO HERO (S1) === */\n.auto-hero::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%233798E4\' fill-opacity=\'0.06\'%3E%3Cpath d=\'M36 34v-4h-2v4h-4v2h4v4h2v-4h4v-2h-4zm0-30V0h-2v4h-4v2h4v4h2V6h4V4h-4zM6 34v-4H4v4H0v2h4v4h2v-4h4v-2H6zM6 4V0H4v4H0v2h4v4h2V6h4V4H6z\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");opacity:0.5}\n.auto-hero{background:linear-gradient(135deg, #000432 0%, #000864 50%, #001080 100%);padding:140px 0 100px;position:relative;overflow:hidden}\n.auto-hero-inner{max-width:1200px;margin:0 auto;padding:0 24px;position:relative;z-index:1;text-align:center}\n.auto-hero-badge{display:inline-flex;align-items:center;gap:8px;background:rgba(0, 175, 240, 0.2);border:1px solid rgba(0, 175, 240, 0.3);padding:8px 20px;border-radius:50px;color:#7EC8F2;font-size:14px;font-weight:500;margin-bottom:24px}\n.auto-hero h1{font-family:\'Noto Sans\', sans-serif;font-size:52px;font-weight:700;color:#fff;margin-bottom:20px;line-height:1.15}\n.auto-hero h1 span{color:#00AFF0}\n.auto-hero-subtitle{font-family:\'Noto Sans\', sans-serif;font-size:20px;color:rgba(255,255,255,0.85);max-width:700px;margin:0 auto 50px;line-height:1.6}\n.auto-hero-stats{display:flex;justify-content:center;gap:60px}\n.auto-hero-stat{text-align:center}\n.auto-hero-stat-value{font-family:\'Noto Sans\', sans-serif;font-size:42px;font-weight:700;color:#00AFF0}\n.auto-hero-stat-label{font-size:14px;color:rgba(255,255,255,0.85);margin-top:4px}\n/* Divi overrides */\n.et_pb_section .auto-hero h1{font-weight:700 !important;line-height:1.15 !important;font-size:52px !important}\n.et_pb_section .auto-hero h1 span{color:#00AFF0 !important}\n.et_pb_section .auto-hero-badge span{font-size:14px !important;font-weight:500 !important;color:#7EC8F2 !important}\n.et_pb_section .auto-hero-subtitle{font-weight:400 !important;font-size:20px !important;line-height:1.6 !important;color:rgba(255,255,255,0.85) !important;padding-bottom:0 !important;max-width:700px !important;margin-bottom:50px !important}\n.et_pb_section .auto-hero-stat-value{font-weight:700 !important;font-size:42px !important;line-height:1 !important;color:#00AFF0 !important}\n.et_pb_section .auto-hero-stat-label{font-size:14px !important;color:rgba(255,255,255,0.85) !important;margin-top:4px !important;padding-bottom:0 !important}\n.et_pb_section .auto-hero-inner p{padding-bottom:0 !important}\n@media (max-width:1024px){.auto-hero h1{font-size:40px}.auto-hero-stats{gap:40px}}\n@media (max-width:640px){.auto-hero{padding:120px 0 80px}.auto-hero h1{font-size:32px}.auto-hero-subtitle{font-size:17px}.auto-hero-stats{flex-direction:column;gap:24px}.auto-hero-stat-value{font-size:36px}}\n/* Defensive SVG sizing */\nsvg:not([width]):not([class]){max-width:48px;max-height:48px}\n@media(prefers-reduced-motion:reduce){}\n/* Super D decoration */\n.dw-d-bg{position:absolute;top:50%;right:auto;left:-15%;width:60%;min-height:60vh;background:url("data:image/svg+xml;base64,") no-repeat center left;background-size:contain;transform:translateY(-50%);opacity:0.15;pointer-events:none;z-index:0}\n/* === CONTEXT (S2) === */\n.context-section{padding:100px 0;background:#fff}\n.context-inner{max-width:900px;margin:0 auto;padding:0 24px;text-align:center}\n.context-inner h2{font-family:\'Noto Sans\', sans-serif;font-size:36px;color:#000864;margin-bottom:24px}\n.context-inner p{font-size:18px;color:#5b6b80;line-height:1.8}\n.context-inner p strong{color:#000864}\n/* Divi overrides */\n.et_pb_section .context-inner h2{font-weight:700 !important;line-height:1.3 !important;font-size:36px !important}\n.et_pb_section .context-inner p{font-weight:400 !important;padding-bottom:0 !important;line-height:1.8 !important;color:#5b6b80 !important}\n.et_pb_section .context-inner p strong{color:#000864 !important;font-weight:700 !important}\n@media(prefers-reduced-motion:reduce){}\n/* === STAKES (S3) === */\n.stakes-section{padding:100px 0;background:#F5F7FA}\n.stakes-inner{max-width:1100px;margin:0 auto;padding:0 24px}\n.stakes-header{text-align:center;margin-bottom:60px}\n.stakes-header h2{font-family:\'Noto Sans\', sans-serif;font-size:36px;color:#000864;margin-bottom:16px}\n.stakes-header p{font-size:18px;color:#5b6b80}\n.stakes-grid{display:grid;grid-template-columns:repeat(3, 1fr);gap:32px}\n.stake-card{background:linear-gradient(145deg, #fef2f2 0%, #fee2e2 100%);border:1px solid #fecaca;border-radius:20px;padding:40px 32px;text-align:center}\n.stake-icon{width:72px;height:72px;background:linear-gradient(135deg, #fee2e2, #fecaca);border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 24px;transition:all 0.4s ease}\n.stake-icon svg{width:32px;height:32px;stroke:#b91c1c;stroke-width:1.5;fill:none}\n.stake-card h3{font-family:\'Noto Sans\', sans-serif;font-size:22px;color:#991b1b;margin-bottom:16px}\n.stake-card p{font-size:15px;color:#b91c1c;line-height:1.7}\n.stake-card:hover .stake-icon{background:linear-gradient(135deg, #00AFF0, #003CC8)}\n.stake-card:hover .stake-icon svg{stroke:#fff}\n/* Divi overrides */\n.et_pb_section .stakes-header h2{font-weight:700 !important;line-height:1.3 !important;font-size:36px !important}\n.et_pb_section .stakes-header p{font-weight:400 !important;padding-bottom:0 !important;line-height:1.6 !important}\n.et_pb_section .stake-card h3{font-weight:700 !important;line-height:1.3 !important;color:#991b1b !important;text-align:center !important}\n.et_pb_section .stake-card p{padding-bottom:0 !important;line-height:1.7 !important;color:#b91c1c !important;text-align:center !important}\n@media (max-width:1024px){.stakes-grid{grid-template-columns:1fr}}\n/* Defensive SVG sizing */\nsvg:not([width]):not([class]){max-width:48px;max-height:48px}\n@media(prefers-reduced-motion:reduce){}\n/* === SOLUTIONS (S4) === */\n.solutions-section{padding:100px 0;background:#fff}\n.solutions-inner{max-width:1100px;margin:0 auto;padding:0 24px}\n.solutions-header{text-align:center;margin-bottom:60px}\n.solutions-header h2{font-family:\'Noto Sans\', sans-serif;font-size:36px;color:#000864;margin-bottom:16px}\n.solutions-header p{font-size:18px;color:#5b6b80}\n.solutions-grid{display:grid;grid-template-columns:repeat(2, 1fr);gap:32px}\n.solution-card{background:#fff;border:1px solid #e2e8f0;border-radius:20px;padding:40px;transition:all 0.3s ease}\n.solution-icon{width:64px;height:64px;background:linear-gradient(135deg, rgba(0, 175, 240, 0.15), rgba(0, 175, 240, 0.05));border-radius:16px;display:flex;align-items:center;justify-content:center;margin-bottom:24px;transition:all 0.4s ease}\n.solution-icon svg{width:28px;height:28px;stroke:#00AFF0;stroke-width:1.5;fill:none}\n.solution-card h3{font-family:\'Noto Sans\', sans-serif;font-size:22px;color:#000864;margin-bottom:12px}\n.solution-card > p{font-size:15px;color:#5b6b80;line-height:1.7;margin-bottom:20px}\n.solution-features{display:flex;flex-direction:column;gap:10px}\n.solution-feature{display:flex;align-items:center;gap:10px;font-size:14px;color:#475569}\n.solution-feature svg{width:18px;height:18px;color:#00AFF0;flex-shrink:0}\n.solution-card:hover{border-color:#00AFF0;box-shadow:0 12px 40px rgba(0, 175, 240, 0.12)}\n.solution-card:hover .solution-icon{background:linear-gradient(135deg, #00AFF0, #003CC8)}\n.solution-card:hover .solution-icon svg{stroke:#fff}\n/* Divi overrides */\n.et_pb_section .solutions-header h2{font-weight:700 !important;line-height:1.3 !important;font-size:36px !important}\n.et_pb_section .solutions-header p{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .solution-card h3{font-weight:700 !important;line-height:1.3 !important;color:#000864 !important}\n.et_pb_section .solution-card > p{padding-bottom:0 !important;line-height:1.7 !important;color:#5b6b80 !important;margin-bottom:20px !important}\n.et_pb_section .solution-feature span{font-size:14px !important;color:#475569 !important}\n@media (max-width:1024px){.solutions-grid{grid-template-columns:1fr}}\n/* Defensive SVG sizing */\nsvg:not([width]):not([class]){max-width:48px;max-height:48px}\n@media(prefers-reduced-motion:reduce){}\n/* Super D: HTML has corner-br at 0.08 opacity */\n.dw-d-bg{position:absolute;top:auto;right:-5%;bottom:-5%;left:auto;width:35%;min-height:40vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;opacity:0.12;pointer-events:none;z-index:0}\n/* === PRODUCTS (S5) === */\n.products-section{padding:100px 0;background:#fff}\n.products-inner{max-width:1100px;margin:0 auto;padding:0 24px}\n.products-header{text-align:center;margin-bottom:60px}\n.products-header h2{font-family:\'Noto Sans\', sans-serif;font-size:36px;color:#000864;margin-bottom:16px}\n.products-grid{display:grid;grid-template-columns:repeat(3, 1fr);gap:24px}\n.product-card{background:#fff;border:2px solid #e2e8f0;border-radius:16px;padding:32px;text-decoration:none;transition:all 0.3s ease;display:block}\n.product-card-icon{width:56px;height:56px;background:linear-gradient(135deg, rgba(0, 175, 240, 0.1), rgba(0, 175, 240, 0.05));border-radius:14px;display:flex;align-items:center;justify-content:center;margin-bottom:20px;transition:all 0.4s ease}\n.product-card-icon svg{width:28px;height:28px;stroke:#00AFF0;stroke-width:1.5;fill:none}\n.product-card h3{font-family:\'Noto Sans\', sans-serif;font-size:20px;color:#000864;margin-bottom:12px}\n.product-card p{font-size:14px;color:#5b6b80;line-height:1.6;margin-bottom:16px}\n.product-card-link{display:inline-flex;align-items:center;gap:6px;color:#00AFF0;font-family:\'Noto Sans\', sans-serif;font-weight:600;font-size:14px}\n.product-card:hover{border-color:#00AFF0;transform:translateY(-4px);box-shadow:0 12px 40px rgba(0, 175, 240, 0.12)}\n.product-card:hover .product-card-icon{background:linear-gradient(135deg, #00AFF0, #003CC8)}\n.product-card:hover .product-card-icon svg{stroke:#fff}\n.product-card:hover .product-card-link{gap:10px}\n/* Divi overrides */\n.et_pb_section .products-header h2{font-weight:700 !important;line-height:1.3 !important;font-size:36px !important}\n.et_pb_section .product-card h3{font-weight:700 !important;line-height:1.3 !important;color:#000864 !important}\n.et_pb_section .product-card p{padding-bottom:0 !important;line-height:1.6 !important;color:#5b6b80 !important}\n.et_pb_section .product-card-link{font-size:14px !important;color:#00AFF0 !important}\n@media (max-width:1024px){.products-grid{grid-template-columns:1fr}}\n/* Defensive SVG sizing */\nsvg:not([width]):not([class]){max-width:48px;max-height:48px}\n@media(prefers-reduced-motion:reduce){}\n/* === RESULTS (S6) === */\n.fade-in{opacity:1;transform:none}\n.fade-in.visible{opacity:1;transform:translateY(0)}\n.fade-in.no-delay{opacity:1;transform:none;transition:none}\n/* Divi overrides for inline-styled elements */\n.et_pb_section .dw-section h2{font-weight:700 !important;line-height:1.3 !important}\n.et_pb_section .dw-section p{padding-bottom:0 !important}\n@media (max-width:1024px){.auto-results-grid{grid-template-columns:repeat(2, 1fr) !important}}\n@media (max-width:600px){.auto-results-grid{grid-template-columns:1fr !important}}\n@media(prefers-reduced-motion:reduce){}\n/* === TRACK RECORD (S7) === */\n.fade-in{opacity:1;transform:none}\n.fade-in.visible{opacity:1;transform:translateY(0)}\n.fade-in.no-delay{opacity:1;transform:none;transition:none}\n/* Divi overrides for inline-styled elements */\n.et_pb_section .dw-section h2{font-weight:700 !important;line-height:1.3 !important}\n.et_pb_section .dw-section h3{font-weight:700 !important;line-height:1.3 !important}\n.et_pb_section .dw-section p{padding-bottom:0 !important}\n@media (max-width:768px){.auto-track-grid{grid-template-columns:1fr !important}}\n@media(prefers-reduced-motion:reduce){}\n/* === SECTION 3 (THAI) === */\n.et_pb_section:has(.auto-faq){padding:60px 0 !important;background:#f8fafc !important}\n.auto-faq{-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.auto-faq p{padding-bottom:0;line-height:1.6}\n.et_pb_section .auto-faq h2{margin:0;padding:0;line-height:1.6}\n.auto-faq summary{-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){}\n/* === CTA: ส่งมอบตามข้อกำหนด OEM อย่างมั่นใจ === */\n.auto-cta-section{background:linear-gradient(135deg, #00AFF0 0%, #003CC8 100%);padding:100px 24px;position:relative;overflow:hidden;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto;font-size:16px}\n.auto-cta-section::before{content:\'\';position:absolute;top:0;left:0;right:0;bottom:0;background-image:url("data:image/svg+xml,%3Csvg width=\'20\' height=\'20\' viewBox=\'0 0 20 20\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cpath d=\'M10 0v20M0 10h20\' stroke=\'%23fff\' stroke-width=\'0.5\' opacity=\'0.05\'/%3E%3C/svg%3E");pointer-events:none;z-index:1}\n.auto-cta-section::after{content:\'\';position:absolute;bottom:-20%;right:-10%;width:80%;height:80%;background:radial-gradient(ellipse at center,rgba(255,255,255,0.1) 0%,transparent 70%);pointer-events:none;z-index:1}\n.auto-cta-super-d{position:absolute;top:auto;right:-5%;bottom:-5%;left:auto;width:35%;min-height:40vh;background:url("data:image/svg+xml;base64,") no-repeat center right;background-size:contain;opacity:0.12;pointer-events:none;z-index:0}\n.auto-cta-wave-flow{position:absolute;bottom:0;left:0;right:0;height:170px;background:linear-gradient(180deg,transparent,rgba(0,60,200,0.15));opacity:0.1;z-index:1;pointer-events:none}\n.auto-cta-container{position:relative;z-index:3;max-width:700px;margin:0 auto;text-align:center}\n.auto-cta-title{font-family:\'Noto Sans\',sans-serif;font-weight:700;font-size:40px;color:#fff;line-height:1.6;margin:0 0 16px}\n.auto-cta-subtitle{font-family:\'Noto Sans\',sans-serif;font-size:20px;color:rgba(255,255,255,0.9);margin:0 0 40px}\n/* Divi overrides — ensure font properties survive Divi cascade */\n.et_pb_section .auto-cta-title{font-weight:700 !important;font-size:40px !important;line-height:1.6 !important;color:#fff !important}\n.et_pb_section .auto-cta-subtitle{font-weight:400 !important;padding-bottom:0 !important}\n.et_pb_section .auto-cta-container p{padding-bottom:0 !important}\n\n.auto-cta-btn{font-family:\'Noto Sans\',sans-serif;font-size:16px;font-weight:600;padding:16px 32px;border-radius:8px;cursor:pointer;transition:all 0.3s ease;text-decoration:none;display:inline-flex;align-items:center;gap:8px;position:relative;overflow:hidden;border:none;line-height:1.6}\n.auto-cta-btn::before{content:\'\';position:absolute;top:0;left:-100%;width:100%;height:100%;background:linear-gradient(90deg,transparent,rgba(255,255,255,0.2),transparent);transition:left 0.5s}\n.auto-cta-btn:hover::before{left:100%}\n.auto-cta-btn--primary{background:#fff;color:#003CC8;font-weight:600;box-shadow:0 4px 20px rgba(0,0,0,0.15)}\n.auto-cta-btn--primary:hover{transform:translateY(-3px);box-shadow:0 12px 40px rgba(0,0,0,0.2)}\n.auto-cta-btn--ghost{background:transparent;color:#fff;border:2px solid rgba(255,255,255,0.6)}\n.auto-cta-btn--ghost:hover{background:rgba(255,255,255,0.15);border-color:#fff}\n.auto-cta-btn-row{display:flex;gap:20px;flex-wrap:wrap;justify-content:center;position:relative;z-index:2}\n.auto-cta-btn{position:static;overflow:visible;display:inline-flex;align-items:center;gap:8px;padding:16px 32px;border-radius:8px;line-height:1.6}\n@media(max-width:767px){\n  .auto-cta-title{font-size:28px;margin-bottom:16px}\n  .auto-cta-subtitle{font-size:16px;margin-bottom:32px}\n  .auto-cta-btn-row{flex-direction:column;align-items:stretch;gap:16px}\n  .auto-cta-btn{width:100%;max-width:300px;margin:0 auto;text-align:center}\n}\n@media(prefers-reduced-motion:reduce){.auto-cta-btn{transition:none !important}.auto-cta-btn::before{display:none}}\n\n.et_pb_section:has(.auto-related-section){background:#F5F7FA;padding:0}\n.auto-related-section{padding:60px 5%;background:#F5F7FA;max-width:100%;-webkit-font-smoothing:auto;-moz-osx-font-smoothing:auto}\n.auto-related-heading{font-family:\'Noto Sans\',sans-serif;font-size:28px;font-weight:600;color:#000864;margin:0 0 32px 0;padding:0;text-align:center;line-height:1.6;-webkit-font-smoothing:auto}\n.auto-related-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(280px,1fr));gap:24px;max-width:1200px;margin:0 auto}\n.auto-related-card{display:block;padding:24px;background:#fff;border-radius:12px;text-decoration:none;border:1px solid #e5e7eb;transition:box-shadow 0.3s ease;color:#333;line-height:1.6}\n.auto-related-card:hover{box-shadow:0 8px 24px rgba(0,8,100,0.1)}\n.auto-related-card-title{font-family:\'Noto Sans\',sans-serif;font-size:18px;font-weight:600;color:#000864;margin:0 0 8px 0;padding:0;line-height:1.6;-webkit-font-smoothing:auto}\n.auto-related-card-desc{font-family:\'Noto Sans\',sans-serif;font-size:14px;color:#666;margin:0;padding:0;line-height:1.5;-webkit-font-smoothing:auto}\n@media(prefers-reduced-motion:reduce){.auto-related-card{transition:none}}\n\n/* === THAI TYPOGRAPHY === */\n/* Font loaded via <link> in header — do NOT use @import here (invalid after rules) */\n\n/* Thai font stack for all body text */\nbody, .et_pb_section, .et_pb_code, .et_pb_code_inner {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n}\n\n/* Thai-specific line heights (Thai script is taller — needs !important to override Divi) */\np, li, .et_pb_text_inner { line-height: 1.8 !important; }\nh1, h2, h3, h4, h5, h6 { line-height: 1.4 !important; }\n\n/* Thai label override: JetBrains Mono doesn\'t have Thai glyphs.\n   letter-spacing breaks Thai script (chars within words must stay connected).\n   text-transform:uppercase is meaningless for Thai. */\n[class*="-label"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n/* Also fix any monospace elements that might contain Thai text */\n[class*="-source"], [class*="-company"] {\n  font-family: \'Noto Sans Thai\', \'Noto Sans\', sans-serif !important;\n  letter-spacing: 0.02em !important;\n  text-transform: none !important;\n}\n\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');

